import requests, json
from bs4 import BeautifulSoup as bs

def get_html(url):
    r = requests.get(url)
    return r.content

def parse_html(html):
    soup = bs(html,'lxml')
    imgs = soup.find('img',{'class':'photo'})['src']
    return imgs

def main():
    url = 'https://www.google.com/'
    html = get_html(url)
    imgs = parse_html(html)
    print(imgs)

if __name__ == '__main__':
    main()

